SELECT COUNT(*) AS annotation_count
FROM annotation_files
WHERE annotator_id = 1;

SELECT COUNT(spect_id) AS spectrogram_count
FROM spectrogram_files
WHERE audio_id = 0;

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT DISTINCT annotator_id
  FROM annotation_files
);

SELECT AVG(a.quality_score) AS average_quality_score
FROM audio_files a
WHERE a.bird_species = 'Gr41rd51';

SELECT bird_species
FROM audio_files
WHERE audio_id = 1;
